function reverseInPlace(arr){
    let left = 0
    let right = arr.length - 1
    while(left < right){
        const tmp = arr[left]
        arr[left] = arr[right]
        arr[right] = tmp
        left++
        right--
    }
    return arr
}

function isPalindrome(text){
    let left = 0
    let right = text.length - 1
    while(left < right){
        if(text[left] !== text[right]) return false
        left++
        right--
    }
    return true
}
